begin;
create table if not exists public.lead_commercial_memory_states(
 id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,broker_id uuid not null references public.profiles(id) on delete restrict,
 memory_version integer not null default 1,interaction_count integer not null default 0,intent_key text not null default 'unknown' check(intent_key in('unknown','moradia','investimento','renda','revenda')),timeline_key text not null default 'unknown' check(timeline_key in('unknown','up_to_3_months','3_to_6_months','6_to_12_months','over_12_months')),
 financing_key text not null default 'unknown' check(financing_key in('unknown','financing','own_resources','exchange','mixed')),objection_keys text[] not null default '{}',signal_keys text[] not null default '{}',stage_key text not null default 'novo',recommended_action_key text not null default 'qualify',
 development_id uuid references public.developments(id) on delete set null,last_interaction_at timestamptz,expires_at timestamptz not null default(now()+interval'180 days'),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(organization_id,lead_id)
);
create table if not exists public.lead_commercial_memory_events(
 id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,memory_id uuid not null references public.lead_commercial_memory_states(id) on delete cascade,broker_id uuid not null references public.profiles(id),event_type text not null check(event_type in('created','updated','reset','owner_changed','expired')),changed_keys text[] not null,actor_id uuid references public.profiles(id),source text not null check(source in('copilot_context','manual_correction','ownership_sync','retention_worker')),reason text,created_at timestamptz not null default now()
);
create index if not exists lead_commercial_memory_owner_idx on public.lead_commercial_memory_states(organization_id,broker_id,updated_at desc);create index if not exists lead_commercial_memory_events_timeline_idx on public.lead_commercial_memory_events(organization_id,lead_id,created_at desc);
alter table public.lead_commercial_memory_states enable row level security;alter table public.lead_commercial_memory_events enable row level security;drop policy if exists lead_commercial_memory_states_scope on public.lead_commercial_memory_states;create policy lead_commercial_memory_states_scope on public.lead_commercial_memory_states for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));drop policy if exists lead_commercial_memory_events_scope on public.lead_commercial_memory_events;create policy lead_commercial_memory_events_scope on public.lead_commercial_memory_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.lead_commercial_memory_states,public.lead_commercial_memory_events from anon;revoke insert,update,delete on public.lead_commercial_memory_states,public.lead_commercial_memory_events from authenticated;grant select on public.lead_commercial_memory_states,public.lead_commercial_memory_events to authenticated;grant all on public.lead_commercial_memory_states,public.lead_commercial_memory_events to service_role;

create or replace function public.record_structured_copilot_memory(p_organization_id uuid,p_lead_id uuid,p_broker_id uuid,p_intent_key text,p_timeline_key text,p_financing_key text,p_objection_keys text[],p_signal_keys text[],p_stage_key text,p_action_key text,p_development_id uuid)
returns jsonb language plpgsql security definer set search_path='' as $$declare memory_row public.lead_commercial_memory_states%rowtype;allowed_objections text[]:=array['price','location','unit','financing','timing','trust','documentation','availability'];allowed_signals text[]:=array['score_high','score_low','stage_advanced','engagement_observed','visit_signal','proposal_signal','recent_interaction','stale_interaction','data_quality_high','data_quality_low','next_action_overdue'];allowed_actions text[]:=array['contact','qualify','present','simulate','schedule_visit','confirm_visit','follow_proposal','validate_documents','close','reactivate'];changed text[]:='{}';
begin if not exists(select 1 from public.leads l where l.id=p_lead_id and l.organization_id=p_organization_id and l.assigned_to=p_broker_id)then raise exception 'structured_memory_owner_mismatch';end if;if p_intent_key not in('unknown','moradia','investimento','renda','revenda')or p_timeline_key not in('unknown','up_to_3_months','3_to_6_months','6_to_12_months','over_12_months')or p_financing_key not in('unknown','financing','own_resources','exchange','mixed')or not coalesce(p_objection_keys,'{}')<@allowed_objections or not coalesce(p_signal_keys,'{}')<@allowed_signals or not p_action_key=any(allowed_actions)then raise exception 'structured_memory_taxonomy_invalid';end if;perform pg_advisory_xact_lock(hashtextextended(p_organization_id::text||':'||p_lead_id::text,0));select*into memory_row from public.lead_commercial_memory_states where organization_id=p_organization_id and lead_id=p_lead_id for update;if not found then insert into public.lead_commercial_memory_states(organization_id,lead_id,broker_id,intent_key,timeline_key,financing_key,objection_keys,signal_keys,stage_key,recommended_action_key,development_id,interaction_count,last_interaction_at)values(p_organization_id,p_lead_id,p_broker_id,p_intent_key,p_timeline_key,p_financing_key,coalesce(p_objection_keys,'{}'),coalesce(p_signal_keys,'{}'),p_stage_key,p_action_key,p_development_id,1,now())returning*into memory_row;changed:=array['intent','timeline','financing','objections','signals','stage','action','development'];insert into public.lead_commercial_memory_events(organization_id,lead_id,memory_id,broker_id,event_type,changed_keys,source)values(p_organization_id,p_lead_id,memory_row.id,p_broker_id,'created',changed,'copilot_context');else if memory_row.broker_id<>p_broker_id then raise exception 'structured_memory_owner_mismatch';end if;if memory_row.intent_key is distinct from p_intent_key then changed:=array_append(changed,'intent');end if;if memory_row.timeline_key is distinct from p_timeline_key then changed:=array_append(changed,'timeline');end if;if memory_row.financing_key is distinct from p_financing_key then changed:=array_append(changed,'financing');end if;if memory_row.objection_keys is distinct from coalesce(p_objection_keys,'{}')then changed:=array_append(changed,'objections');end if;if memory_row.signal_keys is distinct from coalesce(p_signal_keys,'{}')then changed:=array_append(changed,'signals');end if;if memory_row.stage_key is distinct from p_stage_key then changed:=array_append(changed,'stage');end if;if memory_row.recommended_action_key is distinct from p_action_key then changed:=array_append(changed,'action');end if;update public.lead_commercial_memory_states set intent_key=p_intent_key,timeline_key=p_timeline_key,financing_key=p_financing_key,objection_keys=coalesce(p_objection_keys,'{}'),signal_keys=coalesce(p_signal_keys,'{}'),stage_key=p_stage_key,recommended_action_key=p_action_key,development_id=p_development_id,interaction_count=interaction_count+1,memory_version=memory_version+case when cardinality(changed)>0 then 1 else 0 end,last_interaction_at=now(),expires_at=now()+interval'180 days',updated_at=now()where id=memory_row.id returning*into memory_row;if cardinality(changed)>0 then insert into public.lead_commercial_memory_events(organization_id,lead_id,memory_id,broker_id,event_type,changed_keys,source)values(p_organization_id,p_lead_id,memory_row.id,p_broker_id,'updated',changed,'copilot_context');end if;end if;return jsonb_build_object('memoryId',memory_row.id,'version',memory_row.memory_version,'interactionCount',memory_row.interaction_count,'changedKeys',changed,'rawConversationStored',false,'exclusiveLead',true,'exclusiveBroker',true);end $$;

create or replace function public.reset_structured_copilot_memory(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid,p_reason text)returns jsonb language plpgsql security definer set search_path='' as $$declare memory_row public.lead_commercial_memory_states%rowtype;actor_role text;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;select*into memory_row from public.lead_commercial_memory_states where organization_id=p_organization_id and lead_id=p_lead_id for update;if not found or char_length(trim(coalesce(p_reason,'')))<10 or not(actor_role='director'or memory_row.broker_id=p_actor_id)then raise exception 'structured_memory_reset_forbidden';end if;update public.lead_commercial_memory_states set memory_version=memory_version+1,interaction_count=0,intent_key='unknown',timeline_key='unknown',financing_key='unknown',objection_keys='{}',signal_keys='{}',recommended_action_key='qualify',last_interaction_at=null,expires_at=now()+interval'180 days',updated_at=now()where id=memory_row.id;insert into public.lead_commercial_memory_events(organization_id,lead_id,memory_id,broker_id,event_type,changed_keys,actor_id,source,reason)values(p_organization_id,p_lead_id,memory_row.id,memory_row.broker_id,'reset',array['all'],p_actor_id,'manual_correction',trim(p_reason));return jsonb_build_object('memoryId',memory_row.id,'reset',true,'rawConversationStored',false,'reasonRecorded',true);end $$;

update public.lead_copilots set memory=jsonb_build_object('structuredMemory',true,'legacyEntriesPurged',coalesce(jsonb_array_length(case when jsonb_typeof(memory->'recent')='array'then memory->'recent'else'[]'::jsonb end),0),'migratedAt',now())where memory?'recent';
create or replace function private.sync_structured_memory_owner()returns trigger language plpgsql security definer set search_path='' as $$declare m public.lead_commercial_memory_states%rowtype;begin if new.assigned_to is null or new.assigned_to is not distinct from old.assigned_to then return new;end if;update public.lead_commercial_memory_states set broker_id=new.assigned_to,memory_version=memory_version+1,updated_at=now() where organization_id=new.organization_id and lead_id=new.id returning*into m;if found then insert into public.lead_commercial_memory_events(organization_id,lead_id,memory_id,broker_id,event_type,changed_keys,source)values(new.organization_id,new.id,m.id,new.assigned_to,'owner_changed',array['broker'],'ownership_sync');end if;return new;end $$;
drop trigger if exists sync_structured_memory_owner on public.leads;create trigger sync_structured_memory_owner after update of assigned_to on public.leads for each row execute function private.sync_structured_memory_owner();
revoke all on function public.record_structured_copilot_memory(uuid,uuid,uuid,text,text,text,text[],text[],text,text,uuid),public.reset_structured_copilot_memory(uuid,uuid,uuid,text)from public,anon,authenticated;grant execute on function public.record_structured_copilot_memory(uuid,uuid,uuid,text,text,text,text[],text[],text,text,uuid),public.reset_structured_copilot_memory(uuid,uuid,uuid,text)to service_role;
commit;
